def update_json(lang, code, data):
    f_path = os.path.join(frontend_i18n, f'{code}.json')
    if not os.path.exists(f_path):
        return
    with open(f_path, 'r', encoding='utf-8') as f:
        content = json.load(f)
    print(f"Modifying {code}")
    if "DESTINATIONS" not in content:
        content["DESTINATIONS"] = {}
    content["DESTINATIONS"]["DESCRIPTION"] = data
    with open(f_path, 'w', encoding='utf-8') as f:
        json.dump(content, f, ensure_ascii=False, indent=4)

update_json("French", "fr", fr)
update_json("English", "en", en)
update_json("Spanish", "es", es)
update_json("Arabic", "ar", ar)
print("done")
